import{_ as t,o as a,c as i,ae as o}from"./chunks/framework._o5CmwEE.js";const p=JSON.parse('{"title":"Enterprise Security Hardening (Big Tech Standard)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/security-hardening.md","filePath":"guide/security-hardening.md"}'),r={name:"guide/security-hardening.md"};function n(s,e,l,c,u,d){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="enterprise-security-hardening-big-tech-standard" tabindex="-1">Enterprise Security Hardening (Big Tech Standard) <a class="header-anchor" href="#enterprise-security-hardening-big-tech-standard" aria-label="Permalink to &quot;Enterprise Security Hardening (Big Tech Standard)&quot;">​</a></h1><p>This project allows you to scaffold Node.js microservices with enterprise-grade security hardening out of the box. This feature is designed to meet the rigorous security standards of top-tier tech companies.</p><h2 id="🛡️-features-included" tabindex="-1">🛡️ Features Included <a class="header-anchor" href="#🛡️-features-included" aria-label="Permalink to &quot;🛡️ Features Included&quot;">​</a></h2><p>When you select &quot;Yes&quot; for Enterprise Security Hardening during project initialization, the following tools and configurations are added:</p><h3 id="_1-snyk-sca-software-composition-analysis" tabindex="-1">1. Snyk (SCA - Software Composition Analysis) <a class="header-anchor" href="#_1-snyk-sca-software-composition-analysis" aria-label="Permalink to &quot;1. Snyk (SCA - Software Composition Analysis)&quot;">​</a></h3><ul><li><strong>Tool</strong>: <a href="https://snyk.io/" target="_blank" rel="noreferrer">Snyk</a></li><li><strong>Purpose</strong>: Automatically scans your <code>node_modules</code> for known vulnerabilities in third-party dependencies.</li><li><strong>Integration</strong>: <ul><li>A dedicated GitHub Actions workflow (<code>.github/workflows/security.yml</code>).</li><li>GitLab CI and Jenkins stages for automated scanning.</li><li>Fail-safe: CI will fail if &quot;High&quot; or &quot;Critical&quot; vulnerabilities are detected.</li></ul></li></ul><h3 id="_2-sonarcloud-sonarqube-sast-static-application-security-testing" tabindex="-1">2. SonarCloud / SonarQube (SAST - Static Application Security Testing) <a class="header-anchor" href="#_2-sonarcloud-sonarqube-sast-static-application-security-testing" aria-label="Permalink to &quot;2. SonarCloud / SonarQube (SAST - Static Application Security Testing)&quot;">​</a></h3><ul><li><strong>Tool</strong>: <a href="https://sonarcloud.io/" target="_blank" rel="noreferrer">SonarCloud</a></li><li><strong>Purpose</strong>: Deep-dive static analysis to detect code smells, bugs, and security hotspots (e.g., SQL Injection, XSS patterns).</li><li><strong>Integration</strong>: <ul><li>Pre-configured <code>sonar-project.properties</code>.</li><li>Quality Gates enforced in CI/CD pipelines.</li></ul></li></ul><h3 id="_3-husky-pre-commit-quality-gates" tabindex="-1">3. Husky (Pre-commit Quality Gates) <a class="header-anchor" href="#_3-husky-pre-commit-quality-gates" aria-label="Permalink to &quot;3. Husky (Pre-commit Quality Gates)&quot;">​</a></h3><ul><li><strong>Tool</strong>: <a href="https://typicode.github.io/husky/" target="_blank" rel="noreferrer">Husky</a> &amp; <a href="https://github.com/lint-staged/lint-staged" target="_blank" rel="noreferrer">lint-staged</a></li><li><strong>Purpose</strong>: Automatically runs linting and formatting on changed files before every commit to ensure code quality.</li><li><strong>Integration</strong>: <ul><li>Automatically initialized during <code>npm install</code>.</li><li>Prevents &quot;bad code&quot; from being committed to the repository.</li></ul></li></ul><h2 id="🚀-setup-guide" tabindex="-1">🚀 Setup Guide <a class="header-anchor" href="#🚀-setup-guide" aria-label="Permalink to &quot;🚀 Setup Guide&quot;">​</a></h2><p>To fully activate these features in your generated project, follow these steps:</p><h3 id="_1-snyk-setup" tabindex="-1">1. Snyk Setup <a class="header-anchor" href="#_1-snyk-setup" aria-label="Permalink to &quot;1. Snyk Setup&quot;">​</a></h3><ol><li>Create a free account at <a href="https://snyk.io/" target="_blank" rel="noreferrer">Snyk.io</a>.</li><li>Generate a <strong>Snyk API Token</strong>.</li><li>Add the token to your repository secrets: <ul><li><strong>GitHub</strong>: Settings -&gt; Secrets and variables -&gt; Actions -&gt; New repository secret (<code>SNYK_TOKEN</code>).</li><li><strong>GitLab</strong>: Settings -&gt; CI/CD -&gt; Variables (<code>SNYK_TOKEN</code>).</li></ul></li></ol><h3 id="_2-sonarcloud-setup" tabindex="-1">2. SonarCloud Setup <a class="header-anchor" href="#_2-sonarcloud-setup" aria-label="Permalink to &quot;2. SonarCloud Setup&quot;">​</a></h3><ol><li>Create a free account at <a href="https://sonarcloud.io/" target="_blank" rel="noreferrer">SonarCloud.io</a>.</li><li>Create a new project and get your <strong>Project Key</strong> and <strong>Organization</strong>.</li><li>Update <code>sonar-project.properties</code> if necessary.</li><li>Add <code>SONAR_TOKEN</code> to your repository secrets.</li></ol><h3 id="_3-husky-pre-commit-setup" tabindex="-1">3. Husky Pre-commit Setup <a class="header-anchor" href="#_3-husky-pre-commit-setup" aria-label="Permalink to &quot;3. Husky Pre-commit Setup&quot;">​</a></h3><ol><li><strong>Initialize Git</strong>: <code>git init</code> (Must be done before npm install).</li><li><strong>Install</strong>: <code>npm install</code> (Automatically runs the <code>prepare</code> script).</li><li><strong>Usage</strong>: Just try to commit! Husky will automatically run <code>lint-staged</code>.</li></ol><h3 id="_4-running-scans-locally" tabindex="-1">4. Running Scans Locally <a class="header-anchor" href="#_4-running-scans-locally" aria-label="Permalink to &quot;4. Running Scans Locally&quot;">​</a></h3><p>You can run a security audit at any time using:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> security:check</span></span></code></pre></div><p>This command runs <code>npm audit</code> and <code>snyk test</code> in sequence.</p>',22)])])}const h=t(r,[["render",n]]);export{p as __pageData,h as default};
